{
  "name": "Health Behavior Survey - Expert Validation",
  "description": "A professional electronic survey platform for academic research experts to evaluate the Health Behavior Scale for middle school students, featuring multiple dimensions and Arabic RTL support."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface Question {
  id: number;
  text: string;
}

export interface Dimension {
  title: string;
  id: string;
  questions: Question[];
}

export type ExpertResponse = 'suitable' | 'not_suitable' | null;

export interface SurveyState {
  expertName: string;
  academicDegree: string;
  currentJob: string;
  responses: Record<number, ExpertResponse>;
  suggestions: Record<string, string>;
}

import React, { useState, useCallback } from 'react';
import { SURVEY_DIMENSIONS } from './constants';
import { SurveyState, ExpertResponse } from './types';

const App: React.FC = () => {
  const [step, setStep] = useState<'intro' | 'info' | 'survey' | 'summary'>('intro');
  const [activeDimension, setActiveDimension] = useState(0);
  const [formData, setFormData] = useState<SurveyState>({
    expertName: '',
    academicDegree: '',
    currentJob: '',
    responses: {},
    suggestions: {}
  });

  const handleResponseChange = (questionId: number, value: ExpertResponse) => {
    setFormData(prev => ({
      ...prev,
      responses: { ...prev.responses, [questionId]: value }
    }));
  };

  const handleSuggestionChange = (dimensionId: string, value: string) => {
    setFormData(prev => ({
      ...prev,
      suggestions: { ...prev.suggestions, [dimensionId]: value }
    }));
  };

  const nextDimension = () => {
    if (activeDimension < SURVEY_DIMENSIONS.length - 1) {
      setActiveDimension(prev => prev + 1);
      window.scrollTo(0, 0);
    } else {
      setStep('summary');
    }
  };

  const prevDimension = () => {
    if (activeDimension > 0) {
      setActiveDimension(prev => prev - 1);
      window.scrollTo(0, 0);
    }
  };

  const IntroScreen = () => (
    <div className="max-w-4xl mx-auto p-6 text-center animate-fade-in">
      <div className="flex justify-center mb-8">
        <div className="w-24 h-24 bg-blue-600 rounded-full flex items-center justify-center text-white font-bold text-3xl shadow-lg">
          UT
        </div>
      </div>
      <h1 className="text-3xl font-bold mb-4 text-blue-900 academic-font">جامعة طنطا - كلية علوم الرياضة</h1>
      <h2 className="text-xl text-slate-600 mb-8 font-semibold">قسم علوم الصحة الرياضية</h2>

      <div className="bg-white p-8 rounded-2xl shadow-xl border-t-4 border-blue-600 text-right leading-relaxed mb-8">
        <h3 className="text-2xl font-bold mb-6 text-center text-blue-800">إستمارة إستطلاع رآى الخبراء</h3>
        <p className="mb-4">تحية طيبة وبعد ،،،</p>
        <p className="mb-6">
          تقوم الباحثة / <strong>آلاء السيد عبد الحميد سلام</strong> - الباحثة بقسم علوم الصحة الرياضية بكلية علوم الرياضة – جامعة طنطا بإعداد رسالة الماجستير وهى بعنوان :
        </p>
        <div className="bg-blue-50 p-6 rounded-lg border-r-4 border-blue-400 mb-6 italic text-xl font-bold text-center">
          " برنامج تثقيفى غذائى بإستخدام الحاسب الآلى عن مخاطر الوجبات السريعة وتأثيرها على السلوك الصحى لتلميذات المرحلة الثانية من التعليم الأساسى "
        </div>
        <p className="mb-6">
          تهدف هذه الإستمارة إلى وضع العبارات المناسبة لكل بُعد فى مقياس السلوك الصحى الذى يتناسب مع تلميذات الحلقة الثانية من التعليم الأساسى ، والباحثة ترجو من سيادتكم لما لكم من خبرة علمية وعملية كبيرة فى مجال الصحة الرياضية التكرم بإبداء وجهة نظركم فى العبارات المقترحة للمقياس.
        </p>
        <p className="text-center font-bold text-blue-800">وتفضلوا سيادتكم بقبول فائق الاحترام ،،،</p>
      </div>

      <button 
        onClick={() => setStep('info')}
        className="bg-blue-600 hover:bg-blue-700 text-white px-10 py-4 rounded-full font-bold text-xl transition-all transform hover:scale-105 shadow-lg"
      >
        البدء فى تعبئة الإستمارة
      </button>
    </div>
  );

  const InfoScreen = () => (
    <div className="max-w-2xl mx-auto p-6">
      <div className="bg-white p-8 rounded-2xl shadow-xl border-t-4 border-blue-600 animate-slide-up">
        <h3 className="text-2xl font-bold mb-8 text-center text-blue-800">بيانات الخبير</h3>
        <div className="space-y-6">
          <div>
            <label className="block text-right font-bold mb-2 text-slate-700">الاسم واللقب :</label>
            <input 
              type="text" 
              className="w-full p-4 border rounded-xl bg-slate-50 focus:ring-2 focus:ring-blue-500 text-right outline-none"
              value={formData.expertName}
              onChange={e => setFormData({...formData, expertName: e.target.value})}
              placeholder="السيد الأستاذ الدكتور / ..."
            />
          </div>
          <div>
            <label className="block text-right font-bold mb-2 text-slate-700">الدرجة العلمية :</label>
            <input 
              type="text" 
              className="w-full p-4 border rounded-xl bg-slate-50 focus:ring-2 focus:ring-blue-500 text-right outline-none"
              value={formData.academicDegree}
              onChange={e => setFormData({...formData, academicDegree: e.target.value})}
            />
          </div>
          <div>
            <label className="block text-right font-bold mb-2 text-slate-700">الوظيفة الحالية :</label>
            <input 
              type="text" 
              className="w-full p-4 border rounded-xl bg-slate-50 focus:ring-2 focus:ring-blue-500 text-right outline-none"
              value={formData.currentJob}
              onChange={e => setFormData({...formData, currentJob: e.target.value})}
            />
          </div>
        </div>
        <div className="mt-10 flex gap-4">
          <button 
            onClick={() => setStep('survey')}
            className="flex-1 bg-blue-600 hover:bg-blue-700 text-white py-4 rounded-xl font-bold text-lg shadow-md transition-all"
            disabled={!formData.expertName}
          >
            الانتقال للبنود
          </button>
          <button 
            onClick={() => setStep('intro')}
            className="flex-1 bg-slate-200 hover:bg-slate-300 text-slate-700 py-4 rounded-xl font-bold text-lg transition-all"
          >
            رجوع
          </button>
        </div>
      </div>
    </div>
  );

  const SurveyScreen = () => {
    const dim = SURVEY_DIMENSIONS[activeDimension];
    const progress = ((activeDimension + 1) / SURVEY_DIMENSIONS.length) * 100;

    return (
      <div className="max-w-5xl mx-auto p-4 mb-20 animate-fade-in">
        <div className="sticky top-0 bg-white/80 backdrop-blur-md z-10 py-4 mb-6 rounded-b-2xl shadow-sm px-6">
          <div className="flex justify-between items-center mb-2">
            <span className="font-bold text-blue-800">{dim.title}</span>
            <span className="text-slate-500">البُعد {activeDimension + 1} من {SURVEY_DIMENSIONS.length}</span>
          </div>
          <div className="w-full bg-slate-200 h-2 rounded-full overflow-hidden">
            <div className="bg-blue-600 h-full transition-all duration-500" style={{ width: `${progress}%` }}></div>
          </div>
        </div>

        <div className="bg-white rounded-2xl shadow-lg overflow-hidden border border-slate-200">
          <table className="w-full border-collapse">
            <thead className="bg-slate-50">
              <tr>
                <th className="p-4 border-b text-center w-12 text-slate-500">م</th>
                <th className="p-4 border-b text-right text-slate-700">العبـــــــــارة</th>
                <th className="p-4 border-b text-center w-24 text-green-700">مناسب</th>
                <th className="p-4 border-b text-center w-24 text-red-700">غير مناسب</th>
              </tr>
            </thead>
            <tbody>
              {dim.questions.map((q, idx) => (
                <tr key={q.id} className="hover:bg-slate-50 transition-colors">
                  <td className="p-4 border-b text-center text-slate-400 font-bold">{q.id}</td>
                  <td className="p-4 border-b text-right font-medium text-slate-800 leading-relaxed">{q.text}</td>
                  <td className="p-4 border-b text-center">
                    <input 
                      type="radio" 
                      name={`q-${q.id}`} 
                      className="w-5 h-5 cursor-pointer accent-green-600"
                      checked={formData.responses[q.id] === 'suitable'}
                      onChange={() => handleResponseChange(q.id, 'suitable')}
                    />
                  </td>
                  <td className="p-4 border-b text-center">
                    <input 
                      type="radio" 
                      name={`q-${q.id}`} 
                      className="w-5 h-5 cursor-pointer accent-red-600"
                      checked={formData.responses[q.id] === 'not_suitable'}
                      onChange={() => handleResponseChange(q.id, 'not_suitable')}
                    />
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>

        <div className="mt-8 bg-white p-6 rounded-2xl shadow-md border-r-4 border-blue-400">
          <label className="block text-right font-bold mb-3 text-slate-700">مقترحات أخرى تراها سيادتكم لهذا البُعد :</label>
          <textarea 
            className="w-full p-4 border rounded-xl bg-slate-50 min-h-[120px] text-right focus:ring-2 focus:ring-blue-500 outline-none"
            placeholder="اكتب ملاحظاتك أو مقترحاتك هنا..."
            value={formData.suggestions[dim.id] || ''}
            onChange={(e) => handleSuggestionChange(dim.id, e.target.value)}
          />
        </div>

        <div className="mt-10 flex justify-between items-center bg-white p-6 rounded-2xl shadow-lg border-t border-slate-100">
          <button 
            onClick={nextDimension}
            className="bg-blue-600 hover:bg-blue-700 text-white px-8 py-3 rounded-xl font-bold shadow-md transition-all flex items-center gap-2"
          >
            {activeDimension === SURVEY_DIMENSIONS.length - 1 ? 'إنهاء الإستطلاع' : 'البُعد التالى'}
            <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M15 19l-7-7 7-7"/></svg>
          </button>

          <button 
            onClick={prevDimension}
            disabled={activeDimension === 0}
            className={`px-8 py-3 rounded-xl font-bold transition-all flex items-center gap-2 ${activeDimension === 0 ? 'text-slate-300' : 'text-slate-600 hover:bg-slate-100'}`}
          >
            <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9 5l7 7-7 7"/></svg>
            البُعد السابق
          </button>
        </div>
      </div>
    );
  };

  const SummaryScreen = () => (
    <div className="max-w-3xl mx-auto p-6 text-center animate-bounce-in">
      <div className="bg-white p-10 rounded-3xl shadow-2xl border-t-8 border-green-500">
        <div className="w-20 h-20 bg-green-100 text-green-600 rounded-full flex items-center justify-center mx-auto mb-6">
          <svg className="w-12 h-12" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M5 13l4 4L19 7"/></svg>
        </div>
        <h2 className="text-3xl font-bold text-slate-800 mb-4 academic-font">تم إرسال ردكم بنجاح</h2>
        <p className="text-xl text-slate-600 mb-8 leading-relaxed">
          نشكر سيادتكم على مساهمتكم القيمة والتى ستثري البحث العلمي <br/>
          <strong>الأستاذ الدكتور / {formData.expertName}</strong>
        </p>
        <button 
          onClick={() => window.print()}
          className="bg-slate-800 hover:bg-slate-900 text-white px-8 py-3 rounded-xl font-bold mr-4 mb-4 transition-all"
        >
          طباعة ملخص الرد
        </button>
        <button 
          onClick={() => window.location.reload()}
          className="bg-blue-600 hover:bg-blue-700 text-white px-8 py-3 rounded-xl font-bold mb-4 transition-all"
        >
          البدء من جديد
        </button>
      </div>
    </div>
  );

  return (
    <div className="min-h-screen pb-12">
      <header className="bg-white border-b border-slate-200 py-4 mb-8 shadow-sm print:hidden">
        <div className="max-w-6xl mx-auto px-6 flex justify-between items-center">
          <div className="flex items-center gap-4">
            <div className="w-12 h-12 bg-blue-600 rounded-lg flex items-center justify-center text-white font-bold text-xl">UT</div>
            <div className="hidden md:block">
              <h1 className="font-bold text-blue-900 leading-tight">جامعة طنطا</h1>
              <p className="text-xs text-slate-500 font-medium italic">Tanta University</p>
            </div>
          </div>
          <div className="text-right">
             <h2 className="text-sm font-bold text-slate-700">كلية علوم الرياضة</h2>
             <p className="text-xs text-slate-400">إستمارة تحكيم خبير</p>
          </div>
        </div>
      </header>

      <main>
        {step === 'intro' && <IntroScreen />}
        {step === 'info' && <InfoScreen />}
        {step === 'survey' && <SurveyScreen />}
        {step === 'summary' && <SummaryScreen />}
      </main>

      <footer className="mt-20 border-t border-slate-200 py-8 text-center text-slate-400 text-sm print:hidden">
        &copy; {new Date().getFullYear()} جامعة طنطا - كلية علوم الرياضة. جميع الحقوق محفوظة للباحثة.
      </footer>

      <style>{`
        @keyframes fade-in {
          from { opacity: 0; }
          to { opacity: 1; }
        }
        @keyframes slide-up {
          from { transform: translateY(30px); opacity: 0; }
          to { transform: translateY(0); opacity: 1; }
        }
        @keyframes bounce-in {
          0% { transform: scale(0.9); opacity: 0; }
          70% { transform: scale(1.05); opacity: 1; }
          100% { transform: scale(1); }
        }
        .animate-fade-in { animation: fade-in 0.8s ease-out forwards; }
        .animate-slide-up { animation: slide-up 0.6s cubic-bezier(0.16, 1, 0.3, 1) forwards; }
        .animate-bounce-in { animation: bounce-in 0.8s cubic-bezier(0.34, 1.56, 0.64, 1) forwards; }
      `}</style>
    </div>
  );
};

export default App;

{
  "name": "Health Behavior Scale for Students",
  "description": "An interactive health behavior survey for middle school students, featuring a 3-point frequency scale and university branding.",
  "requestFramePermissions": []
}

export interface Question {
  id: number;
  text: string;
}

export interface Dimension {
  title: string;
  id: string;
  questions: Question[];
}

export type StudentResponse = 'always' | 'sometimes' | 'never' | null;

export interface SurveyState {
  studentName: string;
  grade: string;
  school: string;
  responses: Record<number, StudentResponse>;
}

import React, { useState } from 'react';
import { SURVEY_DIMENSIONS } from './constants';
import { SurveyState, StudentResponse } from './types';

const App: React.FC = () => {
  const [step, setStep] = useState<'intro' | 'info' | 'survey' | 'summary'>('intro');
  const [activeDimension, setActiveDimension] = useState(0);
  const [formData, setFormData] = useState<SurveyState>({
    studentName: '',
    grade: '',
    school: '',
    responses: {}
  });

  const handleResponseChange = (questionId: number, value: StudentResponse) => {
    setFormData(prev => ({
      ...prev,
      responses: { ...prev.responses, [questionId]: value }
    }));
  };

  const nextDimension = () => {
    if (activeDimension < SURVEY_DIMENSIONS.length - 1) {
      setActiveDimension(prev => prev + 1);
      window.scrollTo({ top: 0, behavior: 'smooth' });
    } else {
      setStep('summary');
    }
  };

  const prevDimension = () => {
    if (activeDimension > 0) {
      setActiveDimension(prev => prev - 1);
      window.scrollTo({ top: 0, behavior: 'smooth' });
    }
  };

  const IntroScreen = () => (
    <div className="max-w-4xl mx-auto p-6 text-center animate-fade-in">
      <div className="flex justify-center mb-8">
        <div className="w-24 h-24 bg-teal-600 rounded-full flex items-center justify-center text-white font-bold text-3xl shadow-lg border-4 border-white">
          UT
        </div>
      </div>
      <h1 className="text-3xl font-bold mb-4 text-teal-900 academic-font">جامعة طنطا - كلية علوم الرياضة</h1>
      <h2 className="text-2xl font-bold mb-8 text-slate-800">مقياس السلوك الصحى للطالبات</h2>

      <div className="bg-white p-8 rounded-2xl shadow-xl border-t-4 border-teal-600 text-right leading-relaxed mb-8">
        <p className="text-xl mb-6 font-bold text-teal-800 text-center">عزيزتي الطالبة /</p>
        <p className="text-lg mb-6">
          بين يديكِ مجموعة من العبارات التي تصف بعض السلوكيات الصحية اليومية. يهدف هذا المقياس إلى التعرف على عاداتكِ الصحية، ولا توجد إجابات صحيحة أو خاطئة. 
        </p>
        <div className="bg-teal-50 p-6 rounded-lg border-r-4 border-teal-400 mb-6 font-semibold text-slate-700">
          يرجى قراءة كل عبارة بعناية واختيار الإجابة التي تعبر عن حالتكِ بصدق (دائماً - أحياناً - أبداً).
        </div>
        <p className="text-center font-bold text-teal-800 italic">شكراً لتعاونكِ معنا!</p>
      </div>

      <button 
        onClick={() => setStep('info')}
        className="bg-teal-600 hover:bg-teal-700 text-white px-12 py-4 rounded-full font-bold text-xl transition-all transform hover:scale-105 shadow-lg"
      >
        ابدئي الاختبار
      </button>
    </div>
  );

  const InfoScreen = () => (
    <div className="max-w-2xl mx-auto p-6">
      <div className="bg-white p-8 rounded-2xl shadow-xl border-t-4 border-teal-600 animate-slide-up">
        <h3 className="text-2xl font-bold mb-8 text-center text-teal-800">بيانات الطالبة</h3>
        <div className="space-y-6 text-right">
          <div>
            <label className="block font-bold mb-2 text-slate-700">الاسم :</label>
            <input 
              type="text" 
              className="w-full p-4 border rounded-xl bg-slate-50 focus:ring-2 focus:ring-teal-500 text-right outline-none"
              value={formData.studentName}
              onChange={e => setFormData({...formData, studentName: e.target.value})}
              placeholder="اكتبي اسمك هنا..."
            />
          </div>
          <div>
            <label className="block font-bold mb-2 text-slate-700">المدرسة :</label>
            <input 
              type="text" 
              className="w-full p-4 border rounded-xl bg-slate-50 focus:ring-2 focus:ring-teal-500 text-right outline-none"
              value={formData.school}
              onChange={e => setFormData({...formData, school: e.target.value})}
              placeholder="اسم مدرستك..."
            />
          </div>
          <div>
            <label className="block font-bold mb-2 text-slate-700">الصف الدراسي :</label>
            <input 
              type="text" 
              className="w-full p-4 border rounded-xl bg-slate-50 focus:ring-2 focus:ring-teal-500 text-right outline-none"
              value={formData.grade}
              onChange={e => setFormData({...formData, grade: e.target.value})}
              placeholder="مثال: الأول الإعدادي"
            />
          </div>
        </div>
        <div className="mt-10 flex gap-4">
          <button 
            onClick={() => setStep('survey')}
            className="flex-1 bg-teal-600 hover:bg-teal-700 text-white py-4 rounded-xl font-bold text-lg shadow-md transition-all"
            disabled={!formData.studentName || !formData.school}
          >
            استمرار
          </button>
          <button 
            onClick={() => setStep('intro')}
            className="flex-1 bg-slate-200 hover:bg-slate-300 text-slate-700 py-4 rounded-xl font-bold text-lg transition-all"
          >
            رجوع
          </button>
        </div>
      </div>
    </div>
  );

  const SurveyScreen = () => {
    const dim = SURVEY_DIMENSIONS[activeDimension];
    const progress = ((activeDimension + 1) / SURVEY_DIMENSIONS.length) * 100;

    return (
      <div className="max-w-5xl mx-auto p-4 mb-20 animate-fade-in">
        <div className="sticky top-0 bg-white/90 backdrop-blur-md z-10 py-4 mb-6 rounded-b-2xl shadow-sm px-6 border-b border-teal-100">
          <div className="flex justify-between items-center mb-2">
            <span className="font-bold text-teal-800 text-lg">{dim.title}</span>
            <span className="text-slate-500 font-medium">القسم {activeDimension + 1} / {SURVEY_DIMENSIONS.length}</span>
          </div>
          <div className="w-full bg-slate-200 h-3 rounded-full overflow-hidden">
            <div className="bg-teal-500 h-full transition-all duration-500" style={{ width: `${progress}%` }}></div>
          </div>
        </div>

        <div className="bg-white rounded-2xl shadow-lg overflow-hidden border border-slate-200">
          <table className="w-full border-collapse">
            <thead className="bg-teal-50">
              <tr>
                <th className="p-4 border-b text-center w-12 text-slate-500 hidden md:table-cell">م</th>
                <th className="p-4 border-b text-right text-slate-700">العبـــــــــارة</th>
                <th className="p-4 border-b text-center w-20 md:w-32 text-teal-700">دائماً</th>
                <th className="p-4 border-b text-center w-20 md:w-32 text-slate-600">أحياناً</th>
                <th className="p-4 border-b text-center w-20 md:w-32 text-red-600">أبداً</th>
              </tr>
            </thead>
            <tbody>
              {dim.questions.map((q) => (
                <tr key={q.id} className="hover:bg-teal-50/30 transition-colors">
                  <td className="p-4 border-b text-center text-slate-400 font-bold hidden md:table-cell">{q.id}</td>
                  <td className="p-4 border-b text-right font-medium text-slate-800 leading-relaxed">{q.text}</td>
                  <td className="p-4 border-b text-center">
                    <input 
                      type="radio" 
                      name={`q-${q.id}`} 
                      className="w-6 h-6 cursor-pointer accent-teal-600"
                      checked={formData.responses[q.id] === 'always'}
                      onChange={() => handleResponseChange(q.id, 'always')}
                    />
                  </td>
                  <td className="p-4 border-b text-center">
                    <input 
                      type="radio" 
                      name={`q-${q.id}`} 
                      className="w-6 h-6 cursor-pointer accent-slate-600"
                      checked={formData.responses[q.id] === 'sometimes'}
                      onChange={() => handleResponseChange(q.id, 'sometimes')}
                    />
                  </td>
                  <td className="p-4 border-b text-center">
                    <input 
                      type="radio" 
                      name={`q-${q.id}`} 
                      className="w-6 h-6 cursor-pointer accent-red-600"
                      checked={formData.responses[q.id] === 'never'}
                      onChange={() => handleResponseChange(q.id, 'never')}
                    />
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>

        <div className="mt-10 flex justify-between items-center bg-white p-6 rounded-2xl shadow-lg border-t border-slate-100">
          <button 
            onClick={nextDimension}
            className="bg-teal-600 hover:bg-teal-700 text-white px-10 py-4 rounded-xl font-bold shadow-md transition-all flex items-center gap-2 text-lg"
          >
            {activeDimension === SURVEY_DIMENSIONS.length - 1 ? 'إنهاء وحفظ' : 'القسم التالي'}
            <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M15 19l-7-7 7-7"/></svg>
          </button>

          <button 
            onClick={prevDimension}
            disabled={activeDimension === 0}
            className={`px-10 py-4 rounded-xl font-bold transition-all flex items-center gap-2 text-lg ${activeDimension === 0 ? 'text-slate-300' : 'text-slate-600 hover:bg-slate-100'}`}
          >
            <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9 5l7 7-7 7"/></svg>
            السابق
          </button>
        </div>
      </div>
    );
  };

  const SummaryScreen = () => (
    <div className="max-w-3xl mx-auto p-6 text-center animate-bounce-in">
      <div className="bg-white p-10 rounded-3xl shadow-2xl border-t-8 border-teal-500">
        <div className="w-24 h-24 bg-teal-100 text-teal-600 rounded-full flex items-center justify-center mx-auto mb-8 shadow-inner">
          <svg className="w-14 h-14" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M5 13l4 4L19 7"/></svg>
        </div>
        <h2 className="text-3xl font-bold text-slate-800 mb-4 academic-font">تم الانتهاء بنجاح!</h2>
        <p className="text-xl text-slate-600 mb-8 leading-relaxed">
          شكراً لكِ يا <strong>{formData.studentName}</strong> على مشاركتكِ الصادقة.<br/>
          لقد ساعدتنا إجاباتكِ في فهم السلوكيات الصحية بشكل أفضل.
        </p>
        <div className="flex flex-col sm:flex-row gap-4 justify-center">
          <button 
            onClick={() => window.print()}
            className="bg-slate-800 hover:bg-slate-900 text-white px-10 py-4 rounded-xl font-bold transition-all shadow-md"
          >
            طباعة إجاباتكِ
          </button>
          <button 
            onClick={() => window.location.reload()}
            className="bg-teal-600 hover:bg-teal-700 text-white px-10 py-4 rounded-xl font-bold transition-all shadow-md"
          >
            البدء من جديد
          </button>
        </div>
      </div>
    </div>
  );

  return (
    <div className="min-h-screen bg-slate-50 pb-12 overflow-x-hidden">
      <header className="bg-white border-b border-slate-200 py-4 mb-8 shadow-sm print:hidden">
        <div className="max-w-6xl mx-auto px-6 flex justify-between items-center">
          <div className="flex items-center gap-4">
            <div className="w-12 h-12 bg-teal-600 rounded-lg flex items-center justify-center text-white font-bold text-xl shadow-md">UT</div>
            <div className="hidden md:block">
              <h1 className="font-bold text-teal-900 leading-tight">جامعة طنطا</h1>
