};

export default App;

export interface Question {
  id: number;
  text: string;
  isNegative?: boolean;
}

export interface Dimension {
  title: string;
  id: string;
  questions: Question[];
}

export type StudentResponse = 'always' | 'sometimes' | 'never' | null;

export interface DimensionScore {
  title: string;
  score: number;
  maxScore: number;
  percentage: number;
}

export interface Submission {
  id: string;
  timestamp: string;
  studentName: string;
  grade: string;
  school: string;
  totalScore: number;
  maxTotalScore: number;
  dimensionScores: DimensionScore[];
  responses: Record<number, StudentResponse>;
}

export interface SurveyState {
  studentName: string;
  grade: string;
  school: string;
  responses: Record<number, StudentResponse>;
}

import React, { useState, useEffect } from 'react';
import { SURVEY_DIMENSIONS } from './constants';
import { SurveyState, StudentResponse, Submission, DimensionScore } from './types';

const ADMIN_PASSWORD = 'alaa2025';

const App: React.FC = () => {
  const [step, setStep] = useState<'intro' | 'info' | 'survey' | 'summary' | 'admin'>('intro');
  const [activeDimension, setActiveDimension] = useState(0);
  const [isAdminAuth, setIsAdminAuth] = useState(false);
  const [submissions, setSubmissions] = useState<Submission[]>([]);

  const [formData, setFormData] = useState<SurveyState>({
    studentName: '',
    grade: '',
    school: '',
    responses: {}
  });

  // Load submissions from localStorage on mount
  useEffect(() => {
    const saved = localStorage.getItem('alaa_survey_submissions');
    if (saved) {
      setSubmissions(JSON.parse(saved));
    }
  }, []);

  const calculateResults = (): Submission => {
    let totalScore = 0;
    let maxTotalScore = 0;
    const dimensionResults: DimensionScore[] = SURVEY_DIMENSIONS.map(dim => {
      let dimScore = 0;
      let dimMax = dim.questions.length * 2;

      dim.questions.forEach(q => {
        const resp = formData.responses[q.id];
        let val = 0;
        if (resp === 'always') val = q.isNegative ? 0 : 2;
        else if (resp === 'sometimes') val = 1;
        else if (resp === 'never') val = q.isNegative ? 2 : 0;

        dimScore += val;
      });

      totalScore += dimScore;
      maxTotalScore += dimMax;

      return {
        title: dim.title,
        score: dimScore,
        maxScore: dimMax,
        percentage: Math.round((dimScore / dimMax) * 100)
      };
    });

    return {
      id: Math.random().toString(36).substr(2, 9),
      timestamp: new Date().toLocaleString('ar-EG'),
      studentName: formData.studentName,
      grade: formData.grade,
      school: formData.school,
      totalScore,
      maxTotalScore,
      dimensionScores: dimensionResults,
      responses: formData.responses
    };
  };

  const handleFinish = () => {
    const newSubmission = calculateResults();
    const updatedSubmissions = [...submissions, newSubmission];
    setSubmissions(updatedSubmissions);
    localStorage.setItem('alaa_survey_submissions', JSON.stringify(updatedSubmissions));
    setStep('summary');
  };

  const handleResponseChange = (questionId: number, value: StudentResponse) => {
    setFormData(prev => ({
      ...prev,
      responses: { ...prev.responses, [questionId]: value }
    }));
  };

  const nextDimension = () => {
    if (activeDimension < SURVEY_DIMENSIONS.length - 1) {
      setActiveDimension(prev => prev + 1);
      window.scrollTo({ top: 0, behavior: 'smooth' });
    } else {
      handleFinish();
    }
  };

  const loginAdmin = () => {
    const pass = prompt('يرجى إدخال كلمة مرور الباحثة:');
    if (pass === ADMIN_PASSWORD) {
      setIsAdminAuth(true);
      setStep('admin');
    } else {
      alert('كلمة المرور غير صحيحة');
    }
  };

  const exportCSV = () => {
    if (submissions.length === 0) return;
    const headers = ['المعرف', 'الوقت', 'الاسم', 'المدرسة', 'الصف', 'الدرجة الكلية', 'النسبة المئوية'];
    const rows = submissions.map(s => [
      s.id,
      s.timestamp,
      s.studentName,
      s.school,
      s.grade,
      `${s.totalScore}/${s.maxTotalScore}`,
      `${Math.round((s.totalScore / s.maxTotalScore) * 100)}%`
    ]);

    let csvContent = "\uFEFF" + headers.join(",") + "\n" + rows.map(e => e.join(",")).join("\n");
    const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement("a");
    link.setAttribute("href", url);
    link.setAttribute("download", "results_survey.csv");
    document.body.appendChild(link);
    link.click();
  };

  const IntroScreen = () => (
    <div className="max-w-4xl mx-auto p-6 text-center animate-fade-in">
      <div className="flex justify-center mb-8">
        <div className="w-24 h-24 bg-teal-600 rounded-full flex items-center justify-center text-white font-bold text-3xl shadow-lg border-4 border-white">
          UT
        </div>
      </div>
      <h1 className="text-3xl font-bold mb-4 text-teal-900 academic-font">جامعة طنطا - كلية علوم الرياضة</h1>
      <h2 className="text-2xl font-bold mb-8 text-slate-800">مقياس السلوك الصحى للطالبات</h2>

      <div className="bg-white p-8 rounded-2xl shadow-xl border-t-4 border-teal-600 text-right leading-relaxed mb-8">
        <p className="text-xl mb-6 font-bold text-teal-800 text-center">عزيزتي الطالبة /</p>
        <p className="text-lg mb-6">
          بين يديكِ مجموعة من العبارات التي تصف بعض السلوكيات الصحية اليومية. يهدف هذا المقياس إلى التعرف على عاداتكِ الصحية، ولا توجد إجابات صحيحة أو خاطئة. 
        </p>
        <div className="bg-teal-50 p-6 rounded-lg border-r-4 border-teal-400 mb-6 font-semibold text-slate-700">
          يرجى قراءة كل عبارة بعناية واختيار الإجابة التي تعبر عن حالتكِ بصدق (دائماً - أحياناً - أبداً).
        </div>
        <p className="text-center font-bold text-teal-800 italic">شكراً لتعاونكِ معنا!</p>
      </div>

      <button 
        onClick={() => setStep('info')}
        className="bg-teal-600 hover:bg-teal-700 text-white px-12 py-4 rounded-full font-bold text-xl transition-all transform hover:scale-105 shadow-lg"
      >
        ابدئي الاختبار
      </button>
    </div>
  );

  const InfoScreen = () => (
    <div className="max-w-2xl mx-auto p-6">
      <div className="bg-white p-8 rounded-2xl shadow-xl border-t-4 border-teal-600 animate-slide-up">
        <h3 className="text-2xl font-bold mb-8 text-center text-teal-800">بيانات الطالبة</h3>
        <div className="space-y-6 text-right">
          <div>
            <label className="block font-bold mb-2 text-slate-700">الاسم :</label>
            <input 
              type="text" 
              className="w-full p-4 border rounded-xl bg-slate-50 focus:ring-2 focus:ring-teal-500 text-right outline-none"
              value={formData.studentName}
              onChange={e => setFormData({...formData, studentName: e.target.value})}
              placeholder="اكتبي اسمك هنا..."
            />
          </div>
          <div>
            <label className="block font-bold mb-2 text-slate-700">المدرسة :</label>
            <input 
              type="text" 
              className="w-full p-4 border rounded-xl bg-slate-50 focus:ring-2 focus:ring-teal-500 text-right outline-none"
              value={formData.school}
              onChange={e => setFormData({...formData, school: e.target.value})}
              placeholder="اسم مدرستك..."
            />
          </div>
          <div>
            <label className="block font-bold mb-2 text-slate-700">الصف الدراسي :</label>
            <input 
              type="text" 
              className="w-full p-4 border rounded-xl bg-slate-50 focus:ring-2 focus:ring-teal-500 text-right outline-none"
              value={formData.grade}
              onChange={e => setFormData({...formData, grade: e.target.value})}
              placeholder="مثال: الأول الإعدادي"
            />
          </div>
        </div>
        <div className="mt-10 flex gap-4">
          <button 
            onClick={() => setStep('survey')}
            className="flex-1 bg-teal-600 hover:bg-teal-700 text-white py-4 rounded-xl font-bold text-lg shadow-md transition-all"
            disabled={!formData.studentName || !formData.school}
          >
            استمرار
          </button>
          <button 
            onClick={() => setStep('intro')}
            className="flex-1 bg-slate-200 hover:bg-slate-300 text-slate-700 py-4 rounded-xl font-bold text-lg transition-all"
          >
            رجوع
          </button>
        </div>
      </div>
    </div>
  );

  const AdminDashboard = () => (
    <div className="max-w-7xl mx-auto p-6 animate-fade-in">
      <div className="bg-white rounded-3xl shadow-xl overflow-hidden border border-slate-200">
        <div className="bg-slate-800 p-8 text-white flex justify-between items-center">
          <div>
            <h2 className="text-2xl font-bold mb-1">لوحة تحكم الباحثة</h2>
            <p className="text-slate-400">إحصائيات المقياس ونتائج الطالبات</p>
          </div>
          <div className="flex gap-4">
            <button 
              onClick={exportCSV}
              className="bg-green-600 hover:bg-green-700 px-6 py-2 rounded-lg font-bold transition-all flex items-center gap-2"
            >
              تصدير Excel
            </button>
            <button 
              onClick={() => setStep('intro')}
              className="bg-slate-600 hover:bg-slate-700 px-6 py-2 rounded-lg font-bold transition-all"
            >
              خروج
            </button>
          </div>
        </div>

        <div className="p-8">
          <div className="grid grid-cols-1 md:grid-cols-3 gap-6 mb-10">
            <div className="bg-teal-50 p-6 rounded-2xl border border-teal-100">
              <span className="text-teal-600 block mb-2 font-bold">عدد المشاركات</span>
              <span className="text-4xl font-bold text-teal-900">{submissions.length}</span>
            </div>
            <div className="bg-blue-50 p-6 rounded-2xl border border-blue-100">
              <span className="text-blue-600 block mb-2 font-bold">متوسط الدرجة الكلية</span>
              <span className="text-4xl font-bold text-blue-900">
                {submissions.length > 0 
                  ? Math.round(submissions.reduce((acc, s) => acc + (s.totalScore / s.maxTotalScore), 0) / submissions.length * 100) 
                  : 0}%
              </span>
            </div>
          </div>

          <div className="overflow-x-auto">
            <table className="w-full border-collapse">
              <thead>
                <tr className="bg-slate-50 text-right">
                  <th className="p-4 border-b">الطالبة</th>
                  <th className="p-4 border-b">المدرسة / الصف</th>
                  <th className="p-4 border-b">التوقيت</th>
                  <th className="p-4 border-b text-center">الدرجة</th>
                  <th className="p-4 border-b text-center">النسبة</th>
                  <th className="p-4 border-b">تفاصيل الأبعاد</th>
                </tr>
              </thead>
              <tbody>
                {submissions.map(s => (
                  <tr key={s.id} className="hover:bg-slate-50 transition-colors border-b">
                    <td className="p-4 font-bold text-slate-800">{s.studentName}</td>
                    <td className="p-4 text-slate-600">{s.school} - {s.grade}</td>
                    <td className="p-4 text-slate-500 text-sm">{s.timestamp}</td>
                    <td className="p-4 text-center font-bold text-teal-700">{s.totalScore} / {s.maxTotalScore}</td>
                    <td className="p-4 text-center">
                      <span className="bg-teal-100 text-teal-800 px-3 py-1 rounded-full text-xs font-bold">
                        {Math.round((s.totalScore / s.maxTotalScore) * 100)}%
                      </span>
                    </td>
                    <td className="p-4">
                      <div className="flex gap-1">
                        {s.dimensionScores.map((ds, i) => (
                          <div key={i} className="w-8 h-4 bg-slate-200 rounded-full overflow-hidden" title={`${ds.title}: ${ds.percentage}%`}>
                            <div className="h-full bg-teal-500" style={{ width: `${ds.percentage}%` }}></div>
                          </div>
                        ))}
                      </div>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      </div>
    </div>
  );

  return (
    <div className="min-h-screen bg-slate-50 pb-12 overflow-x-hidden">
      <header className="bg-white border-b border-slate-200 py-4 mb-8 shadow-sm print:hidden">
        <div className="max-w-6xl mx-auto px-6 flex justify-between items-center">
          <div className="flex items-center gap-4">
            <div className="w-12 h-12 bg-teal-600 rounded-lg flex items-center justify-center text-white font-bold text-xl shadow-md">UT</div>
            <div className="hidden md:block">
              <h1 className="font-bold text-teal-900 leading-tight">جامعة طنطا</h1>
              <p className="text-xs text-slate-500 font-medium italic">Tanta University</p>
            </div>
          </div>
          <div className="text-right">
             <h2 className="text-sm font-bold text-slate-700">كلية علوم الرياضة</h2>
             <p className="text-xs text-teal-600 font-bold">مقياس السلوك الصحي</p>
          </div>
        </div>
      </header>

      <main>
        {step === 'intro' && <IntroScreen />}
        {step === 'info' && <InfoScreen />}
        {step === 'survey' && (
          <SurveyScreen 
            activeDimension={activeDimension} 
            formData={formData} 
            handleResponseChange={handleResponseChange}
            nextDimension={nextDimension}
            prevDimension={() => setActiveDimension(d => d - 1)}
          />
        )}
        {step === 'summary' && <SummaryScreen studentName={formData.studentName} submission={calculateResults()} />}
        {step === 'admin' && isAdminAuth && <AdminDashboard />}
      </main>

      <footer className="mt-20 border-t border-slate-200 py-8 text-center text-slate-400 text-sm print:hidden relative">
        <p>&copy; {new Date().getFullYear()} جامعة طنطا - كلية علوم الرياضة.</p>
        <button 
          onClick={loginAdmin}
          className="absolute left-6 bottom-6 opacity-20 hover:opacity-100 transition-opacity p-2 text-slate-400"
          title="لوحة التحكم"
        >
          <svg className="w-6 h-6" fill="currentColor" viewBox="0 0 20 20"><path fillRule="evenodd" d="M5 9V7a5 5 0 0110 0v2a2 2 0 012 2v5a2 2 0 01-2 2H5a2 2 0 01-2-2v-5a2 2 0 012-2zm8-2v2H7V7a3 3 0 016 0z" clipRule="evenodd"/></svg>
        </button>
      </footer>

      <style>{`
        @keyframes fade-in { from { opacity: 0; } to { opacity: 1; } }
        @keyframes slide-up { from { transform: translateY(40px); opacity: 0; } to { transform: translateY(0); opacity: 1; } }
