        .animate-fade-in { animation: fade-in 0.7s ease-out forwards; }
        .animate-slide-up { animation: slide-up 0.5s ease-out forwards; }
        .animate-bounce-in { animation: bounce-in 0.7s cubic-bezier(0.34, 1.56, 0.64, 1) forwards; }
      `}</style>
    </div>
  );
};

// Sub-components for cleaner App.tsx
const SurveyScreen = ({ activeDimension, formData, handleResponseChange, nextDimension, prevDimension }: any) => {
  const dim = SURVEY_DIMENSIONS[activeDimension];
  const progress = ((activeDimension + 1) / SURVEY_DIMENSIONS.length) * 100;

  return (
    <div className="max-w-5xl mx-auto p-4 mb-20 animate-fade-in">
      <div className="sticky top-0 bg-white/90 backdrop-blur-md z-10 py-4 mb-6 rounded-b-2xl shadow-sm px-6 border-b border-teal-100">
        <div className="flex justify-between items-center mb-2">
          <span className="font-bold text-teal-800 text-lg">{dim.title}</span>
          <span className="text-slate-500 font-medium">القسم {activeDimension + 1} / {SURVEY_DIMENSIONS.length}</span>
        </div>
        <div className="w-full bg-slate-200 h-3 rounded-full overflow-hidden">
          <div className="bg-teal-500 h-full transition-all duration-500" style={{ width: `${progress}%` }}></div>
        </div>
      </div>

      <div className="bg-white rounded-2xl shadow-lg overflow-hidden border border-slate-200">
        <table className="w-full border-collapse">
          <thead className="bg-teal-50">
            <tr>
