{
  "name": "Health Behavior Scale - Researcher Edition",
  "description": "A comprehensive health behavior scale for students with a secret researcher dashboard for data tracking and statistics."
}

import React, { useState, useEffect } from 'react';
import { SURVEY_DIMENSIONS } from './constants';
import { SurveyState, StudentResponse, Submission, DimensionScore } from './types';

const ADMIN_PASSWORD = 'alaa2025';
const RESEARCHER_PHONE = '201000000000'; // استبدلي هذا برقم الواتساب الخاص بكِ

const App: React.FC = () => {
  const [step, setStep] = useState<'intro' | 'info' | 'survey' | 'summary' | 'admin'>('intro');
  const [activeDimension, setActiveDimension] = useState(0);
  const [isAdminAuth, setIsAdminAuth] = useState(false);
  const [submissions, setSubmissions] = useState<Submission[]>([]);

  const [formData, setFormData] = useState<SurveyState>({
    studentName: '',
    grade: '',
    school: '',
    responses: {}
  });

  useEffect(() => {
    const saved = localStorage.getItem('alaa_survey_data');
    if (saved) {
      setSubmissions(JSON.parse(saved));
    }
  }, []);

  const calculateResults = (): Submission => {
    let totalScore = 0;
    let maxTotalScore = 0;
    const dimensionResults: DimensionScore[] = SURVEY_DIMENSIONS.map(dim => {
      let dimScore = 0;
      let dimMax = dim.questions.length * 2;

      dim.questions.forEach(q => {
        const resp = formData.responses[q.id];
        let val = 0;
        if (resp === 'always') val = q.isNegative ? 0 : 2;
        else if (resp === 'sometimes') val = 1;
        else if (resp === 'never') val = q.isNegative ? 2 : 0;
        dimScore += val;
      });

      totalScore += dimScore;
      maxTotalScore += dimMax;

      return {
        title: dim.title,
        score: dimScore,
        maxScore: dimMax,
        percentage: Math.round((dimScore / dimMax) * 100)
      };
    });

    return {
      id: Math.random().toString(36).substr(2, 9),
      timestamp: new Date().toLocaleString('ar-EG'),
      studentName: formData.studentName,
      grade: formData.grade,
      school: formData.school,
      totalScore,
      maxTotalScore,
      dimensionScores: dimensionResults,
      responses: formData.responses
    };
  };

  const saveSubmission = () => {
    const result = calculateResults();
    const updated = [result, ...submissions];
    setSubmissions(updated);
    localStorage.setItem('alaa_survey_data', JSON.stringify(updated));
    setStep('summary');
  };

  const sendToWhatsApp = () => {
    const res = calculateResults();
    const message = `نتائج مقياس السلوك الصحي%0Aالاسم: ${res.studentName}%0Aالمدرسة: ${res.school}%0Aالصف: ${res.grade}%0Aالدرجة الكلية: ${res.totalScore} من ${res.maxTotalScore}%0Aالنسبة: ${Math.round((res.totalScore/res.maxTotalScore)*100)}%`;
    window.open(`https://wa.me/${RESEARCHER_PHONE}?text=${message}`, '_blank');
  };

  const handleResponseChange = (questionId: number, value: StudentResponse) => {
    setFormData(prev => ({
      ...prev,
      responses: { ...prev.responses, [questionId]: value }
    }));
  };

  const nextDimension = () => {
    const dim = SURVEY_DIMENSIONS[activeDimension];
    const allAnswered = dim.questions.every(q => formData.responses[q.id]);

    if (!allAnswered) {
      alert('يرجى الإجابة على جميع العبارات في هذا القسم قبل الانتقال');
      return;
    }

    if (activeDimension < SURVEY_DIMENSIONS.length - 1) {
      setActiveDimension(prev => prev + 1);
      window.scrollTo({ top: 0, behavior: 'smooth' });
    } else {
      saveSubmission();
    }
  };

  const loginAdmin = () => {
    const pass = prompt('كلمة مرور الباحثة:');
    if (pass === ADMIN_PASSWORD) {
      setIsAdminAuth(true);
      setStep('admin');
    }
  };

  // Views
  const Intro = () => (
