          </div>
        </div>
        <button onClick={() => setStep('survey')} disabled={!formData.studentName || !formData.school} className="w-full mt-10 bg-teal-600 hover:bg-teal-700 text-white py-4 rounded-xl font-bold text-lg shadow-md transition-all disabled:opacity-50">دخول المقياس</button>
      </div>
