                  <td className="p-5 text-center">
                    <input type="radio" name={`q-${q.id}`} className="w-6 h-6 accent-red-500 cursor-pointer scale-125" checked={formData.responses[q.id] === 'never'} onChange={() => handleResponseChange(q.id, 'never')} />
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>

        <div className="p-8 bg-slate-50 flex justify-between items-center border-t">
          <button onClick={onNext} className="bg-teal-600 hover:bg-teal-700 text-white px-12 py-4 rounded-2xl font-bold text-xl shadow-lg transition-transform active:scale-95">
            {activeDimension === 5 ? 'إرسال وتسجيل النتائج' : 'القسم التالي'}
          </button>
          <button onClick={onBack} disabled={activeDimension === 0} className="text-slate-400 hover:text-slate-800 font-bold text-lg disabled:opacity-20 px-4 py-2">
            السابق
          </button>
        </div>
      </div>
    </div>
  );
};

