import React, { useState, useEffect, useCallback } from 'react';
import { SURVEY_DIMENSIONS } from './constants';
import { SurveyState, StudentResponse, Submission, DimensionScore } from './types';

const ADMIN_PASSWORD = 'alaa2025';
const STORAGE_KEY = 'alaa_research_data_v1';

const App: React.FC = () => {
  const [mode, setMode] = useState<'selection' | 'student' | 'researcher_login' | 'researcher'>('selection');
  const [step, setStep] = useState<'intro' | 'info' | 'survey' | 'summary'>('intro');
  const [activeDimension, setActiveDimension] = useState(0);
  const [submissions, setSubmissions] = useState<Submission[]>([]);
  const [selectedSubmission, setSelectedSubmission] = useState<Submission | null>(null);
  const [loginPass, setLoginPass] = useState('');
  const [loginError, setLoginError] = useState(false);

  const [formData, setFormData] = useState<SurveyState>({
    studentName: '',
    grade: '',
    school: '',
    responses: {}
  });

  // Function to load data directly from localStorage
  const loadLatestSubmissions = useCallback(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    if (saved) {
      try {
        const parsed = JSON.parse(saved);
        if (Array.isArray(parsed)) {
          setSubmissions(parsed);
          return parsed;
        }
      } catch (e) {
        console.error("Error loading data", e);
      }
    }
    return [];
  }, []);

  // Initial load
  useEffect(() => {
    loadLatestSubmissions();
  }, [loadLatestSubmissions]);

  const calculateResults = (): Submission => {
    let totalScore = 0;
    let maxTotalScore = 0;
    const dimensionResults: DimensionScore[] = SURVEY_DIMENSIONS.map(dim => {
      let dimScore = 0;
      let dimMax = dim.questions.length * 2;

      dim.questions.forEach(q => {
        const resp = formData.responses[q.id];
        let val = 0;
        if (resp === 'always') val = q.isNegative ? 0 : 2;
        else if (resp === 'sometimes') val = 1;
        else if (resp === 'never') val = q.isNegative ? 2 : 0;
        dimScore += val;
      });

      totalScore += dimScore;
      maxTotalScore += dimMax;

      return {
        title: dim.title,
        score: dimScore,
        maxScore: dimMax,
        percentage: Math.round((dimScore / dimMax) * 100)
      };
    });

    return {
      id: Math.random().toString(36).substr(2, 9),
      timestamp: new Date().toLocaleString('ar-EG'),
      studentName: formData.studentName || 'غير معروف',
      grade: formData.grade || 'غير معروف',
      school: formData.school || 'غير معروف',
      totalScore,
      maxTotalScore,
      dimensionScores: dimensionResults,
      responses: { ...formData.responses }
    };
  };

  const handleFinishSurvey = () => {
    const newResult = calculateResults();

    // Always read latest from disk to avoid race conditions with state
    const currentOnDisk = loadLatestSubmissions();
    const updated = [newResult, ...currentOnDisk];

    // Save to disk first
    localStorage.setItem(STORAGE_KEY, JSON.stringify(updated));
    // Then update state
    setSubmissions(updated);
    setStep('summary');
  };

  const handleLogin = (e?: React.FormEvent) => {
    if (e) e.preventDefault();
    if (loginPass === ADMIN_PASSWORD) {
      // Re-load data just before entering dashboard to ensure fresh view
      loadLatestSubmissions();
      setMode('researcher');
      setLoginPass('');
      setLoginError(false);
    } else {
      setLoginError(true);
      setTimeout(() => setLoginError(false), 3000);
    }
  };

  const exportToExcel = () => {
    const headers = ['الاسم', 'المدرسة', 'الصف', 'التوقيت', 'الدرجة الكلية', 'النسبة المئوية'];
    const rows = submissions.map(s => [
      s.studentName, s.school, s.grade, s.timestamp, s.totalScore, 
      `${Math.round((s.totalScore / s.maxTotalScore) * 100)}%`
    ]);
    const csvContent = "\uFEFF" + [headers, ...rows].map(e => e.join(",")).join("\n");
    const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
    const link = document.createElement("a");
    link.href = URL.createObjectURL(blob);
    link.download = `نتائج_مقياس_آلاء_السيد_${new Date().toLocaleDateString('ar-EG')}.csv`;
    link.click();
  };

  // --- UI Layouts ---

  if (mode === 'selection') {
    return (
      <div className="min-h-screen bg-slate-50 flex flex-col items-center justify-center p-6 animate-fade-in">
        <div className="w-24 h-24 bg-teal-600 rounded-full flex items-center justify-center text-white font-bold text-3xl mb-8 shadow-2xl border-4 border-white">UT</div>
        <h1 className="text-4xl font-bold mb-4 text-teal-900 academic-font text-center">مقياس السلوك الصحي الرقمي</h1>
        <p className="text-slate-500 mb-12 text-lg text-center">جامعة طنطا - كلية علوم الرياضة</p>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-8 w-full max-w-2xl mb-12">
          <button 
            onClick={() => { setMode('student'); setStep('intro'); }}
            className="bg-white p-10 rounded-3xl shadow-xl hover:shadow-2xl transition-all border-b-8 border-teal-500 group text-center"
          >
            <div className="w-20 h-20 bg-teal-50 rounded-2xl flex items-center justify-center mx-auto mb-6 group-hover:bg-teal-500 group-hover:text-white transition-colors">
              <svg className="w-10 h-10" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 14l9-5-9-5-9 5 9 5z"/><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 14l6.16-3.422a12.083 12.083 0 01.665 6.479A11.952 11.952 0 0012 20.055a11.952 11.952 0 00-6.824-2.998 12.078 12.078 0 01.665-6.479L12 14z"/></svg>
            </div>
            <h3 className="text-2xl font-bold text-slate-800">دخول الطالبة</h3>
            <p className="text-slate-500 mt-2">البدء في تعبئة المقياس</p>
          </button>

          <button 
            onClick={() => setMode('researcher_login')}
            className="bg-white p-10 rounded-3xl shadow-xl hover:shadow-2xl transition-all border-b-8 border-slate-700 group text-center"
          >
            <div className="w-20 h-20 bg-slate-50 rounded-2xl flex items-center justify-center mx-auto mb-6 group-hover:bg-slate-700 group-hover:text-white transition-colors">
              <svg className="w-10 h-10" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9 19v-6a2 2 0 00-2-2H5a2 2 0 00-2 2v6a2 2 0 002 2h2a2 2 0 002-2zm0 0V9a2 2 0 012-2h2a2 2 0 012 2v10m-6 0a2 2 0 002 2h2a2 2 0 002-2m0 0V5a2 2 0 012-2h2a2 2 0 012 2v14a2 2 0 01-2 2h-2a2 2 0 01-2-2z"/></svg>
            </div>
            <h3 className="text-2xl font-bold text-slate-800">لوحة الباحثة</h3>
            <p className="text-slate-500 mt-2">مشاهدة الإحصائيات والنتائج</p>
          </button>
        </div>

        <div className="bg-slate-200/50 px-6 py-2 rounded-full text-slate-500 text-sm font-medium">
          يوجد حالياً <span className="text-teal-600 font-bold">{submissions.length}</span> طالبات مسجلات في الذاكرة
        </div>
      </div>
    );
  }

  if (mode === 'researcher_login') {
    return (
      <div className="min-h-screen bg-slate-100 flex items-center justify-center p-6 animate-fade-in">
        <div className="bg-white w-full max-w-md p-10 rounded-[2.5rem] shadow-2xl border-t-8 border-slate-800 text-center">
          <div className="w-20 h-20 bg-slate-100 rounded-3xl flex items-center justify-center mx-auto mb-8 text-slate-600">
            <svg className="w-10 h-10" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 15v2m-6 4h12a2 2 0 002-2v-6a2 2 0 00-2-2H6a2 2 0 00-2 2v6a2 2 0 002 2zm10-10V7a4 4 0 00-8 0v4h8z"/></svg>
          </div>
          <h3 className="text-2xl font-bold text-slate-800 mb-2">تسجيل دخول الباحثة</h3>
          <p className="text-slate-500 mb-8">يرجى إدخال كلمة المرور للوصول للنتائج</p>

          <form onSubmit={handleLogin} className="space-y-4">
            <input 
              autoFocus
              type="password" 
              placeholder="••••••••"
              className={`w-full p-4 border-2 rounded-2xl text-center text-2xl outline-none transition-all ${loginError ? 'border-red-500 bg-red-50' : 'border-slate-100 focus:border-slate-800'}`}
              value={loginPass}
              onChange={e => setLoginPass(e.target.value)}
            />
            {loginError && <p className="text-red-500 font-bold text-sm animate-pulse">كلمة المرور غير صحيحة!</p>}
            <div className="flex gap-4 pt-4">
              <button type="submit" className="flex-1 bg-slate-800 text-white py-4 rounded-2xl font-bold hover:bg-black transition-all shadow-lg active:scale-95">دخول</button>
              <button type="button" onClick={() => setMode('selection')} className="flex-1 bg-slate-100 text-slate-600 py-4 rounded-2xl font-bold hover:bg-slate-200 transition-all">إلغاء</button>
            </div>
          </form>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-slate-50">
      <header className="bg-white border-b border-slate-200 py-4 shadow-sm sticky top-0 z-40">
        <div className="max-w-7xl mx-auto px-6 flex justify-between items-center">
          <div className="flex items-center gap-4">
            <div className="w-10 h-10 bg-teal-600 rounded-lg flex items-center justify-center text-white font-bold">UT</div>
            <h1 className="font-bold text-teal-900 hidden md:block">جامعة طنطا - كلية علوم الرياضة</h1>
          </div>
          <div className="text-right">
            <h2 className="text-sm font-bold text-slate-700">الباحثة: آلاء السيد سلام</h2>
            <p className="text-xs text-teal-600 font-bold">نظام القياس الصحي الذكي</p>
          </div>
        </div>
      </header>

      <main className="py-10 px-6">
        {mode === 'student' && (
          <div className="max-w-7xl mx-auto">
            {step === 'intro' && <IntroView onNext={() => setStep('info')} />}
            {step === 'info' && <InfoForm formData={formData} setFormData={setFormData} onNext={() => setStep('survey')} onBack={() => setMode('selection')} />}
            {step === 'survey' && <SurveyRunner 
              activeDimension={activeDimension} 
              formData={formData} 
              handleResponseChange={(id, val) => setFormData(p => ({...p, responses: {...p.responses, [id]: val}}))}
              onNext={() => {
                const dim = SURVEY_DIMENSIONS[activeDimension];
                if (!dim.questions.every(q => formData.responses[q.id])) return alert('يرجى إكمال جميع العبارات في هذا القسم');
                if (activeDimension < SURVEY_DIMENSIONS.length - 1) {
                  setActiveDimension(d => d + 1);
                  window.scrollTo(0,0);
                } else handleFinishSurvey();
              }}
              onBack={() => setActiveDimension(d => d - 1)}
            />}
            {step === 'summary' && <SuccessView submission={calculateResults()} studentName={formData.studentName} />}
          </div>
        )}

        {mode === 'researcher' && (
          <ResearcherDashboard 
            submissions={submissions} 
            exportToExcel={exportToExcel} 
            onExit={() => { loadLatestSubmissions(); setMode('selection'); }} 
            onRefresh={loadLatestSubmissions}
            selectedSubmission={selectedSubmission}
            setSelectedSubmission={setSelectedSubmission}
          />
        )}
      </main>

      <footer className="py-8 text-center text-slate-400 text-sm">
        <p>© {new Date().getFullYear()} جامعة طنطا - جميع البيانات محفوظة ومحمية</p>
      </footer>

