      <div className="space-y-6 text-right">
        <div><label className="block font-bold mb-2">الاسم بالكامل:</label><input type="text" className="w-full p-4 border rounded-2xl bg-slate-50 focus:border-teal-500 outline-none text-right" value={formData.studentName} onChange={e => setFormData({...formData, studentName: e.target.value})} placeholder="..." /></div>
        <div><label className="block font-bold mb-2">المدرسة:</label><input type="text" className="w-full p-4 border rounded-2xl bg-slate-50 focus:border-teal-500 outline-none text-right" value={formData.school} onChange={e => setFormData({...formData, school: e.target.value})} placeholder="..." /></div>
