const SurveyRunner = ({ activeDimension, formData, handleResponseChange, onNext, onBack }: any) => {
  const dim = SURVEY_DIMENSIONS[activeDimension];
  const progress = ((activeDimension + 1) / SURVEY_DIMENSIONS.length) * 100;
  return (
    <div className="max-w-5xl mx-auto animate-fade-in pb-20">
      <div className="bg-white rounded-[2.5rem] shadow-2xl overflow-hidden">
        <div className="bg-teal-600 p-8 text-white">
          <h3 className="text-2xl font-bold mb-4">{dim.title}</h3>
          <div className="w-full bg-black/10 h-3 rounded-full overflow-hidden"><div className="bg-white h-full transition-all duration-1000" style={{ width: `${progress}%` }}></div></div>
        </div>
        <div className="overflow-x-auto">
          <table className="w-full text-right">
            <thead className="bg-slate-50">
              <tr className="text-slate-500 font-bold">
                <th className="p-6 border-b w-16">م</th>
                <th className="p-6 border-b">العبارة</th>
                <th className="p-6 border-b text-center w-24">دائماً</th>
                <th className="p-6 border-b text-center w-24">أحياناً</th>
                <th className="p-6 border-b text-center w-24">أبداً</th>
              </tr>
            </thead>
            <tbody>
              {dim.questions.map((q) => (
                <tr key={q.id} className="border-b hover:bg-teal-50/20">
                  <td className="p-6 text-slate-300 font-bold">{q.id}</td>
                  <td className="p-6 font-medium text-lg">{q.text}</td>
                  <td className="p-6 text-center"><input type="radio" name={`q-${q.id}`} className="w-6 h-6 accent-teal-600" checked={formData.responses[q.id] === 'always'} onChange={() => handleResponseChange(q.id, 'always')} /></td>
                  <td className="p-6 text-center"><input type="radio" name={`q-${q.id}`} className="w-6 h-6 accent-slate-400" checked={formData.responses[q.id] === 'sometimes'} onChange={() => handleResponseChange(q.id, 'sometimes')} /></td>
                  <td className="p-6 text-center"><input type="radio" name={`q-${q.id}`} className="w-6 h-6 accent-red-500" checked={formData.responses[q.id] === 'never'} onChange={() => handleResponseChange(q.id, 'never')} /></td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
        <div className="p-10 bg-slate-50 flex justify-between items-center">
