            <p className="text-xs text-teal-600 font-bold">نظام القياس الصحي الذكي</p>
          </div>
        </div>
      </header>

      <main className="py-10 px-6">
        {mode === 'student' && (
          <div className="max-w-7xl mx-auto">
            {step === 'intro' && <IntroView onNext={() => setStep('info')} />}
            {step === 'info' && <InfoForm formData={formData} setFormData={setFormData} onNext={() => setStep('survey')} onBack={() => setMode('selection')} />}
            {step === 'survey' && <SurveyRunner activeDimension={activeDimension} formData={formData} handleResponseChange={(id, val) => setFormData(p => ({...p, responses: {...p.responses, [id]: val}}))} onNext={() => {
              const dim = SURVEY_DIMENSIONS[activeDimension];
              if (!dim.questions.every(q => formData.responses[q.id])) return alert('يرجى إكمال جميع العبارات');
              if (activeDimension < SURVEY_DIMENSIONS.length - 1) { setActiveDimension(d => d + 1); window.scrollTo(0,0); } else handleFinishSurvey();
            }} onBack={() => setActiveDimension(d => d - 1)} />}
            {step === 'summary' && <SuccessView submission={calculateResults()} studentName={formData.studentName} onFinish={resetToHome} />}
          </div>
        )}
        {mode === 'researcher' && (
          <ResearcherDashboard submissions={submissions} exportToExcel={exportToExcel} onExit={resetToHome} onRefresh={loadAndMigrateData} selectedSubmission={selectedSubmission} setSelectedSubmission={setSelectedSubmission} />
