              <p className="text-teal-700 text-lg md:text-xl font-black">آلاء السيد سلام</p>
            </div>

            <div className="bg-white p-4 md:p-6 rounded-2xl md:rounded-[2rem] border border-slate-100 shadow-sm max-w-sm md:max-w-xl mx-auto">
