              </div>
            </div>
          </div>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-4 md:gap-8 w-full max-w-2xl mb-8">
          <button 
            onClick={() => { setMode('student'); setStep('intro'); }}
