                <div className="flex gap-3 md:gap-4 pt-4">
                  <button type="submit" className="flex-1 bg-slate-800 text-white py-3 md:py-4 rounded-xl md:rounded-2xl font-bold hover:bg-black transition-all">دخول</button>
