                      formData.responses[q.id] === opt.id 
                      ? (opt.color === 'teal' ? 'bg-teal-600 border-teal-600 text-white shadow-md scale-105' : 
                         opt.color === 'red' ? 'bg-red-500 border-red-500 text-white shadow-md scale-105' : 
